from flask import Flask, request, jsonify
from flask_sqlalchemy import SQLAlchemy
from flask_limiter import Limiter
from itsdangerous import URLSafeTimedSerializer
import os
import smtplib
import random
import string

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///users.db'
db = SQLAlchemy(app)
limiter = Limiter(app, key_func=lambda: request.remote_addr)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(120), unique=True, nullable=False)
    reset_token = db.Column(db.String(120), nullable=True)

@app.route('/reset-password', methods=['POST'])
@limiter.limit("5 per minute")
def reset_password():
    email = request.json.get('email')
    user = User.query.filter_by(email=email).first()
    
    if user:
        token = ''.join(random.choices(string.ascii_letters + string.digits, k=32))
        user.reset_token = token
        db.session.commit()
        
        reset_link = f"http://localhost:5000/reset-password-confirm?token={token}"
        send_email(email, reset_link)
        
    return jsonify({"message": "If the email is registered, a reset link has been sent."}), 200

def send_email(to_email, reset_link):
    from_email = os.getenv('EMAIL_USER')
    password = os.getenv('EMAIL_PASS')
    with smtplib.SMTP('smtp.gmail.com', 587) as server:
        server.starttls()
        server.login(from_email, password)
        message = f"Subject: Password Reset\n\nClick the link to reset your password: {reset_link}"
        server.sendmail(from_email, to_email, message)

if __name__ == '__main__':
    db.create_all()
    app.run(debug=True)